queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?servicename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasBanks ?parent . } GROUP BY ?child }
  ?child p:serviceName ?servicename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Banks } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?servicename WHERE {
  ?banks_services a :Banks_Services .
  ?services a :Services .
  ?banks_services p:hasServices ?services .
  ?banks a :Banks .
  ?banks_services p:hasBanks ?banks .
  ?banks p:name ?name .
  ?services p:serviceName ?servicename .
} }
  collective: { SELECT ?servicename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasBanks ?parent . } GROUP BY ?child }
  ?child p:serviceName ?servicename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Banks } }
  FILTER(?nf = ?total)
} }
}
